const tickMinutes = Math.max(1, Number($env.PLAN_SCHEDULER_TICK_MINUTES || 60));
const now = new Date();
const minuteBucket = Math.floor(now.getTime() / 60000);
const tickDue = minuteBucket % tickMinutes === 0;

const baseUrl = String($env.CONTENT_ENGINE_URL || '').replace(/\/$/, '');
if (!baseUrl) {
  throw new Error('Missing CONTENT_ENGINE_URL env var');
}

const internalToken = String($env.INTERNAL_API_TOKEN || '').trim();
if (!internalToken) {
  throw new Error('Missing INTERNAL_API_TOKEN env var');
}

const nf = (typeof fetch === 'function') ? null : require('node-fetch');
const fetchFn = (typeof fetch === 'function') ? fetch : (nf.default || nf);
const url = baseUrl + '/api/internal/sites/automation-targets';

const response = await fetchFn(url, {
  method: 'GET',
  headers: {
    'x-internal-token': internalToken,
  },
});

const raw = await response.text();
let parsed = {};
try {
  parsed = raw ? JSON.parse(raw) : {};
} catch (error) {
  throw new Error('Invalid automation-targets response: ' + raw.slice(0, 220));
}

if (!response.ok || !parsed.ok || !Array.isArray(parsed.targets)) {
  throw new Error('Cannot resolve automation targets: ' + (parsed.error || raw || response.status));
}

const schedulerRunBase = 'plan-scheduler-' + now.toISOString().replace(/[:.]/g, '-');
const siteSlugs = parsed.targets
  .map((value) => String(value || '').toLowerCase().trim())
  .filter((value) => value.length > 0);

if (!siteSlugs.length) {
  return [];
}

return siteSlugs.map((siteSlug) => ({
  json: {
    siteSlug,
    triggerType: 'schedule',
    reason: tickDue ? 'scheduled_tick' : 'scheduled_tick_skipped',
    force: false,
    tickDue,
    skipTick: !tickDue,
    tickMinutes,
    runsThisTick: 0,
    noWorkNeeded: !tickDue,
    note: tickDue ? '' : 'Tick skipped by PLAN_SCHEDULER_TICK_MINUTES gate',
    schedulerRunId: schedulerRunBase + '-' + siteSlug,
  }
}));

const root = (typeof $json === 'object' && $json) ? $json : {};
const body = (root.body && typeof root.body === 'object') ? root.body : root;
const headers = (root.headers && typeof root.headers === 'object') ? root.headers : {};
const expectedInternalToken = String($env.INTERNAL_API_TOKEN || '').trim();
const providedInternalToken = String(headers['x-internal-token'] || headers['X-Internal-Token'] || '').trim();
if (!expectedInternalToken) {
  throw new Error('INTERNAL_API_TOKEN is required for plan-automation webhook');
}
if (providedInternalToken !== expectedInternalToken) {
  throw new Error('Unauthorized plan-automation webhook call');
}

const siteSlug = String(body.siteSlug || root.siteSlug || '').toLowerCase().trim();
if (!siteSlug) throw new Error('Missing siteSlug in plan scheduler webhook payload');
const reason = String(body.reason || 'manual_trigger');
const now = new Date();

return {
  json: {
    siteSlug,
    triggerType: 'webhook',
    reason,
    force: true,
    tickDue: true,
    skipTick: false,
    tickMinutes: Math.max(1, Number($env.PLAN_SCHEDULER_TICK_MINUTES || 60)),
    schedulerRunId: `plan-scheduler-${now.toISOString().replace(/[:.]/g, '-')}`
  }
};

function toMs(value) {
  if (!value) return null;
  const ms = new Date(value).getTime();
  return Number.isNaN(ms) ? null : ms;
}

const sourceItems = (typeof $input !== 'undefined' && $input && typeof $input.all === 'function')
  ? $input.all()
  : (typeof items !== 'undefined' ? items : []);
function getNodeJson(nodeName) {
  try {
    if (typeof $(nodeName).all === 'function') {
      const allItems = $(nodeName).all();
      if (Array.isArray(allItems) && allItems[0] && typeof allItems[0].json === 'object') {
        return allItems[0].json;
      }
    }
  } catch (error) {
    // ignore
  }

  try {
    if ($(nodeName).item && typeof $(nodeName).item.json === 'object') {
      return $(nodeName).item.json;
    }
  } catch (error) {
    // ignore
  }

  return {};
}

const webhookCtx = getNodeJson('Build webhook payload');
const scheduleCtx = getNodeJson('Build scheduled payload');
const triggerCtx = (webhookCtx.siteSlug && webhookCtx.triggerType === 'webhook') ? webhookCtx : scheduleCtx;

const base = {
  ...triggerCtx,
  ...(sourceItems[0] ? sourceItems[0].json || {} : {})
};
const entitlementSnap = $('Fetch entitlement snapshot').item.json || {};
const quota = entitlementSnap.quota || {};
const publishedListRes = $('Fetch recent published list').item.json || {};
const recentPublished = Array.isArray(publishedListRes.result) ? publishedListRes.result : [];
const briefReadyRes = $('Fetch brief_ready topics count').item.json || {};
const briefReadyCount = Math.max(0, Number(briefReadyRes.result || 0));

const siteSlug = String(base.siteSlug || entitlementSnap.siteSlug || '').toLowerCase().trim();
if (!siteSlug) throw new Error('Missing siteSlug in scheduler planning context');
const now = Date.now();
const force = Boolean(base.force);
const triggerType = String(base.triggerType || 'schedule');
const reason = String(base.reason || 'scheduled_tick');
const schedulerRunId = String(base.schedulerRunId || ('plan-scheduler-' + new Date().toISOString().replace(/[:.]/g, '-')));
const refillIntervalMinutes = Math.max(1, Number($env.PLAN_TOPIC_REFILL_INTERVAL_MINUTES || 15));
const minuteBucketNow = Math.floor(now / 60000);
const refillDueNow = force || (minuteBucketNow % refillIntervalMinutes === 0);


if (briefReadyCount <= 0) {
  return [{
    json: {
      siteSlug,
      briefReadyCount,
      schedulerRunId,
      triggerType,
      reason,
      plan: String(entitlementSnap.plan || 'base').toLowerCase(),
      monthlyQuota: Math.max(0, Number((entitlementSnap.quota || {}).monthlyQuota || 0)),
      publishedThisMonth: Math.max(0, Number((entitlementSnap.quota || {}).publishedThisMonth || 0)),
      refillDue: refillDueNow,
      refillIntervalMinutes,
      noWorkNeeded: true,
      runsThisTick: 0,
      note: 'No brief_ready topics available'
    }
  }];
}

if (base.skipTick === true) {
  return [{
    json: {
      siteSlug,
      schedulerRunId,
      triggerType,
      reason,
      runsThisTick: 0,
      noWorkNeeded: true,
      note: base.note || 'Tick skipped by PLAN_SCHEDULER_TICK_MINUTES gate'
    }
  }];
}

if (!entitlementSnap.ok) {
  return [{ json: { siteSlug, schedulerRunId, triggerType, reason, noWorkNeeded: true, note: 'Entitlement endpoint returned non-ok payload' } }];
}

const publishingEnabled = entitlementSnap.publishingEnabled !== false;
const plan = String(entitlementSnap.plan || 'base').toLowerCase();
const status = String(entitlementSnap.status || 'active').toLowerCase();
const monthlyQuota = Math.max(0, Number(quota.monthlyQuota || 0));
const publishedThisMonth = Math.max(0, Number(quota.publishedThisMonth || 0));
const periodStartMs = toMs(quota.periodStart);
const periodEndMs = toMs(quota.periodEnd);

const maxRunsPerTick = Math.max(1, Number($env.PLAN_SCHEDULER_MAX_RUNS_PER_TICK || 2));
const dailyCaps = {
  base: Math.max(1, Number($env.PLAN_SCHEDULER_DAILY_CAP_BASE || 1)),
  standard: Math.max(1, Number($env.PLAN_SCHEDULER_DAILY_CAP_STANDARD || 2)),
  pro: Math.max(1, Number($env.PLAN_SCHEDULER_DAILY_CAP_PRO || 4))
};
const dailyCap = dailyCaps[plan] || dailyCaps.base;

const todayStart = new Date();
todayStart.setHours(0, 0, 0, 0);
const todayStartMs = todayStart.getTime();
const todayCount = recentPublished.reduce((count, item) => {
  const ms = toMs(item.publishedAt);
  return ms !== null && ms >= todayStartMs ? count + 1 : count;
}, 0);

if (!publishingEnabled || status !== 'active' || monthlyQuota <= 0) {
  return [{
    json: {
      siteSlug,
      briefReadyCount,
      schedulerRunId,
      triggerType,
      reason,
      plan,
      monthlyQuota,
      publishedThisMonth,
      todayCount,
      dailyCap,
      noWorkNeeded: true,
      note: 'Publishing disabled, inactive entitlement, or zero quota'
    }
  }];
}

const monthlyRemaining = Math.max(0, monthlyQuota - publishedThisMonth);
const dailyRemaining = Math.max(0, dailyCap - todayCount);

const testMode = String($env.PLAN_SCHEDULER_TEST_MODE || 'false').toLowerCase() === 'true';
if (testMode) {
  const planIntervals = {
    base: Math.max(1, Number($env.PLAN_TEST_INTERVAL_MINUTES_BASE || 3)),
    standard: Math.max(1, Number($env.PLAN_TEST_INTERVAL_MINUTES_STANDARD || 2)),
    pro: Math.max(1, Number($env.PLAN_TEST_INTERVAL_MINUTES_PRO || 1))
  };
  const intervalMinutes = planIntervals[plan] || planIntervals.base;
  const intervalStartMs = now - intervalMinutes * 60_000;
  const publishedInInterval = recentPublished.some((item) => {
    const ms = toMs(item.publishedAt);
    return ms !== null && ms >= intervalStartMs;
  });

  const runsThisTick = force
    ? Math.max(0, Math.min(1, monthlyRemaining, dailyRemaining, maxRunsPerTick))
    : (publishedInInterval ? 0 : Math.max(0, Math.min(1, monthlyRemaining, dailyRemaining, maxRunsPerTick)));

  if (runsThisTick <= 0) {
    return [{
      json: {
        siteSlug,
        briefReadyCount,
        schedulerRunId,
        triggerType,
        reason,
        plan,
        monthlyQuota,
        publishedThisMonth,
        monthlyRemaining,
        todayCount,
        dailyCap,
        dailyRemaining,
        maxRunsPerTick,
        runsThisTick,
        testMode: true,
        intervalMinutes,
        noWorkNeeded: true,
        note: publishedInInterval ? 'Test mode interval gate not elapsed yet' : 'No runs allowed by quota/caps'
      }
    }];
  }

  return [{
    json: {
      siteSlug,
      schedulerRunId,
      triggerType,
      reason,
      plan,
      monthlyQuota,
      publishedThisMonth,
      monthlyRemaining,
      todayCount,
      dailyCap,
      dailyRemaining,
      maxRunsPerTick,
      runsThisTick,
      runIndex: 1,
      testMode: true,
      intervalMinutes,
      noWorkNeeded: false,
      pipelineMode: 'prepopulate_bulk_direct'
    }
  }];
}

let elapsedRatio = 1;
if (periodStartMs !== null && periodEndMs !== null && periodEndMs > periodStartMs) {
  elapsedRatio = Math.min(1, Math.max(0, (now - periodStartMs) / (periodEndMs - periodStartMs)));
}

const expectedByNow = Math.floor(monthlyQuota * elapsedRatio);
let missing = Math.max(0, Math.min(monthlyRemaining, expectedByNow - publishedThisMonth));

if (force && missing <= 0 && monthlyRemaining > 0) {
  missing = 1;
}

const runsThisTick = Math.max(0, Math.min(missing, dailyRemaining, maxRunsPerTick));

if (runsThisTick <= 0) {
  return [{
    json: {
      siteSlug,
      schedulerRunId,
      triggerType,
      reason,
      plan,
      monthlyQuota,
      publishedThisMonth,
      monthlyRemaining,
      expectedByNow,
      elapsedRatio,
      todayCount,
      dailyCap,
      dailyRemaining,
      maxRunsPerTick,
      runsThisTick,
      noWorkNeeded: true,
      note: 'No runs needed on this tick'
    }
  }];
}

return Array.from({ length: runsThisTick }, (_, idx) => ({
  json: {
    siteSlug,
    briefReadyCount,
    schedulerRunId,
    triggerType,
    reason,
    plan,
    monthlyQuota,
    publishedThisMonth,
    monthlyRemaining,
    expectedByNow,
    elapsedRatio,
    todayCount,
    dailyCap,
    dailyRemaining,
    maxRunsPerTick,
    runsThisTick,
    runIndex: idx + 1,
    noWorkNeeded: false,
    pipelineMode: 'prepopulate_bulk_direct'
  }
}));

const allItems = (typeof $input !== 'undefined' && $input && typeof $input.all === 'function')
  ? $input.all()
  : (typeof items !== 'undefined' ? items : []);
const rows = allItems.map((item) => item.json || {});

let planCtx = {};
try {
  const planItems = $('Plan runs for this tick').all();
  planCtx = planItems[0]?.json || {};
} catch (error) {
  planCtx = {};
}

const first = rows[0] || {};
const ctx = { ...first, ...planCtx };

return [{
  json: {
    workflowName: 'plan_generation_scheduler_worker',
    timestamp: new Date().toISOString(),
    siteSlug: ctx.siteSlug || null,
    schedulerRunId: ctx.schedulerRunId || null,
    triggerType: ctx.triggerType || 'schedule',
    reason: ctx.reason || 'scheduled_tick',
    plan: ctx.plan || null,
    monthlyQuota: Number(ctx.monthlyQuota || 0),
    publishedThisMonth: Number(ctx.publishedThisMonth || 0),
    expectedByNow: Number(ctx.expectedByNow || 0),
    runsThisTick: Number(ctx.runsThisTick || rows.length || 0),
    executedRuns: rows.length,
    note: 'Plan-based generation scheduler executed.'
  }
}];

const current = (typeof $json === 'object' && $json) ? $json : {};
let gate = {};
try {
  gate = ($('Need topic refill?').item && $('Need topic refill?').item.json) ? $('Need topic refill?').item.json : {};
} catch (error) {
  gate = {};
}

const merged = { ...gate, ...current };
let note = merged.note || 'No generation needed on this tick';
if (merged.ok === true && note === 'No brief_ready topics available') {
  note = 'Auto-refill triggered: new topic candidates generated';
}

return {
  json: {
    workflowName: 'plan_generation_scheduler_worker',
    timestamp: new Date().toISOString(),
    siteSlug: merged.siteSlug || null,
    schedulerRunId: merged.schedulerRunId || null,
    triggerType: merged.triggerType || 'schedule',
    reason: merged.reason || 'scheduled_tick',
    plan: merged.plan || null,
    monthlyQuota: Number(merged.monthlyQuota || 0),
    publishedThisMonth: Number(merged.publishedThisMonth || 0),
    expectedByNow: Number(merged.expectedByNow || 0),
    runsThisTick: Number(merged.runsThisTick || 0),
    noWorkNeeded: true,
    note
  }
};

const incoming = (typeof $json === 'object' && $json) ? $json : {};
const body = incoming.body && typeof incoming.body === 'object' ? incoming.body : {};
const payload = incoming.payload && typeof incoming.payload === 'object' ? incoming.payload : {};
const siteSlug = String(
  incoming.siteSlug ||
  incoming.site_slug ||
  body.siteSlug ||
  payload.siteSlug ||
  ''
).trim().toLowerCase();
if (!siteSlug) {
  throw new Error('Missing siteSlug for Resolve Site Context');
}

const baseUrl = String($env.CONTENT_ENGINE_URL || '').replace(/\/$/, '');
if (!baseUrl) {
  throw new Error('Missing CONTENT_ENGINE_URL env var');
}

const internalToken = String($env.INTERNAL_API_TOKEN || '').trim();
if (!internalToken) {
  throw new Error('Missing INTERNAL_API_TOKEN env var');
}

const nf = (typeof fetch === 'function') ? null : require('node-fetch');
const fetchFn = (typeof fetch === 'function') ? fetch : (nf.default || nf);
const url = baseUrl + '/api/internal/sites/' + encodeURIComponent(siteSlug) + '/sanity-connection';

const response = await fetchFn(url, {
  method: 'GET',
  headers: {
    'x-internal-token': internalToken,
  },
});

const raw = await response.text();
let parsed = {};
try {
  parsed = raw ? JSON.parse(raw) : {};
} catch (error) {
  throw new Error('Invalid sanity-connection response for ' + siteSlug + ': ' + raw.slice(0, 220));
}

if (!response.ok || !parsed.ok || !parsed.sanity) {
  throw new Error('Cannot resolve site Sanity connection for ' + siteSlug + ': ' + (parsed.error || raw || response.status));
}

const sanity = parsed.sanity || {};
if (!sanity.projectId || !sanity.readToken || !sanity.writeToken) {
  throw new Error('Incomplete site Sanity connection for ' + siteSlug);
}

return {
  json: {
    ...incoming,
    siteSlug: parsed.siteSlug || siteSlug,
    sanity,
  }
};
